export type Cell = [number, number];

const cellKey = ([x, y]: Cell): string => `${x},${y}`;

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const aliveKeys = new Set(liveCells.map(cellKey));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const neighbor: Cell = [x + dx, y + dy];
        const k = cellKey(neighbor);
        const entry = neighborCounts.get(k);
        if (entry) {
          entry.count++;
        } else {
          neighborCounts.set(k, { cell: neighbor, count: 1 });
        }
      }
    }
  }

  const nextLiveCells: Cell[] = [];
  for (const [k, { cell, count }] of neighborCounts) {
    if (count === 3 || (count === 2 && aliveKeys.has(k))) {
      nextLiveCells.push(cell);
    }
  }
  return nextLiveCells;
}

export type Cell = [number, number];

const cellKey = ([x, y]: Cell): string => `${x},${y}`;

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const aliveKeys = new Set(liveCells.map(cellKey));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const neighbor: Cell = [x + dx, y + dy];
        const k = cellKey(neighbor);
        const prior = neighborCounts.get(k)?.count ?? 0;
        neighborCounts.set(k, { cell: neighbor, count: prior + 1 });
      }
    }
  }

  const nextLiveCells: Cell[] = [];
  for (const [k, { cell, count }] of neighborCounts) {
    if (count === 3 || (count === 2 && aliveKeys.has(k))) {
      nextLiveCells.push(cell);
    }
  }
  return nextLiveCells;
}
